3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const tallyNeighborCounts = (liveCells: Cell[]): Map<string, [Cell, number]> => {
15	  const counts = new Map<string, [Cell, number]>();
16	  for (const cell of liveCells) {
17	    for (const neighbor of neighborsOf(cell)) {
18	      const key = cellKey(neighbor);
19	      const prior = counts.get(key)?.[1] ?? 0;
20	      counts.set(key, [neighbor, prior + 1]);
21	    }
22	  }
23	  return counts;
24	};
25	
26	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
27	  const liveSet = new Set(liveCells.map(cellKey));
28	  const survivesOrBorn = ([cell, count]: [Cell, number]): boolean =>
29	    count === 3 || (count === 2 && liveSet.has(cellKey(cell)));
30	
31	  return [...tallyNeighborCounts(liveCells).values()]
32	    .filter(survivesOrBorn)
33	    .map(([cell]) => cell);
34	};
