const tallyNeighborCounts = (liveCells: Cell[]): Map<string, [Cell, number]> => {
  const counts = new Map<string, [Cell, number]>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const prior = counts.get(key)?.[1] ?? 0;
      counts.set(key, [neighbor, prior + 1]);
    }
  }
  return counts;
};

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(cellKey));
  const isAliveNext = (key: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(key));

  return [...tallyNeighborCounts(liveCells)]
    .filter(([key, [, count]]) => isAliveNext(key, count))
    .map(([, [cell]]) => cell);
};
